"use strict";(self.webpackChunkdocs=self.webpackChunkdocs||[]).push([[132],{23378:e=>{e.exports=JSON.parse('{"functions":[{"name":"Default","desc":"Standard Jitter function that randomly varies from the center value +- the spread.\\n\\n```lua\\nlocal myJitter = Jitter.Default(1, 0.15)\\n\\nlocal sound1 = ...\\nsound1.PlaybackSpeed = myJitter() -- Sets a random value.\\n\\nlocal sound2 = ...\\nsound2.PlaybackSpeed = myJitter() -- Sets another random value.\\n```","params":[{"name":"center","desc":"The central value around which the jitter will occur.","lua_type":"number"},{"name":"spread","desc":"The maximum deviation from the center value.","lua_type":"number"}],"returns":[{"desc":"Generates the jitter value when called.","lua_type":"() -> number"}],"function_type":"static","source":{"line":40,"path":"lib/Sections/Jitter.luau"}},{"name":"Range","desc":"Essentially just a random number that requires a specified range.\\n\\n```lua\\nlocal myJitter = Jitter.Range(0.85, 1.15)\\n\\nlocal sound1 = ...\\nsound1.PlaybackSpeed = myJitter() -- Sets a random value.\\n\\nlocal sound2 = ...\\nsound2.PlaybackSpeed = myJitter() -- Sets another random value.\\n```","params":[{"name":"min","desc":"The minimum value for the jitter range.","lua_type":"number"},{"name":"max","desc":"The maximum value for the jitter range.","lua_type":"number"}],"returns":[{"desc":"Generates the jitter value when called.","lua_type":"() -> number"}],"function_type":"static","source":{"line":68,"path":"lib/Sections/Jitter.luau"}},{"name":"Scale","desc":"Very similar to `Jitter.Default` but the center value is 1.\\n\\n```lua\\nlocal myJitter = Jitter.Scale(0.15)\\n\\nlocal sound1 = ...\\nsound1.PlaybackSpeed = myJitter() -- Sets a random value.\\n\\nlocal sound2 = ...\\nsound2.PlaybackSpeed = myJitter() -- Sets another random value.\\n```","params":[{"name":"spread","desc":"The maximum deviation from the center value.","lua_type":"number"}],"returns":[{"desc":"Generates the jitter value when called.","lua_type":"() -> number"}],"function_type":"static","source":{"line":95,"path":"lib/Sections/Jitter.luau"}},{"name":"UnitLog","desc":"Produces jitter values with a shaped distribution that favors the center value.\\n\\n```lua\\nlocal myJitter = Jitter.UnitLog(1, 0.15)\\n\\nlocal sound1 = ...\\nsound1.PlaybackSpeed = myJitter() -- Sets a random shaped value.\\n\\nlocal sound2 = ...\\nsound2.PlaybackSpeed = myJitter() -- Sets another random shaped value.\\n```\\n\\n:::tip\\n\\tThis can be used to make more natural repetitious sounds like footsteps.\\n:::","params":[{"name":"center","desc":"The central value around which the jitter will occur.","lua_type":"number"},{"name":"spread","desc":"The maximum deviation from the center value.","lua_type":"number"}],"returns":[{"desc":"Generates the jitter value when called.","lua_type":"() -> number"}],"function_type":"static","source":{"line":127,"path":"lib/Sections/Jitter.luau"}}],"properties":[],"types":[],"name":"Jitter","desc":"Jitter functions meant for Volume and Pitch properties of sounds. Can be used in other contexts as well.\\n\\n:::info\\nAll jitter functions are clamped from 0 to 10.\\n:::","source":{"line":18,"path":"lib/Sections/Jitter.luau"}}')}}]);